ALTER TABLE users MODIFY COLUMN role ENUM('admin', 'patient', 'pharmacist', 'med_rep', 'lab', 'delivery', 'medical_services') NOT NULL DEFAULT 'patient'; 
CREATE TABLE IF NOT EXISTS medical_service_providers (id INT AUTO_INCREMENT PRIMARY KEY, owner_user_id INT, name VARCHAR(255) NOT NULL, name_ar VARCHAR(255), address TEXT, wilaya VARCHAR(100), city VARCHAR(100), phone VARCHAR(30), email VARCHAR(255), description TEXT, is_verified TINYINT(1) DEFAULT 0, rating FLOAT DEFAULT 4.0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; 
CREATE TABLE IF NOT EXISTS medical_services (id INT AUTO_INCREMENT PRIMARY KEY, provider_id INT, provider_user_id INT, name VARCHAR(255), name_ar VARCHAR(255), category VARCHAR(100), price DECIMAL(10,2), description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; 
